import{_ as l,C as a,o as i,c as p,a2 as o,E as r,j as e,a as d}from"./chunks/framework.e-meDy3u.js";const T=JSON.parse('{"title":"Q7 · 30 天怎么证明价值？","description":"","frontmatter":{},"headers":[],"relativePath":"q7.md","filePath":"q7.md"}'),q={name:"q7.md"};function u(h,t,_,c,g,m){const n=a("DeliveryTable"),s=a("Timeline");return i(),p("div",null,[t[0]||(t[0]=o('<h1 id="q7-·-30-天怎么证明价值" tabindex="-1">Q7 · 30 天怎么证明价值？ <a class="header-anchor" href="#q7-·-30-天怎么证明价值" aria-label="Permalink to &quot;Q7 · 30 天怎么证明价值？&quot;">​</a></h1><p class="hqq-lede">30 天价值证明的关键：承诺可控的事，对不可控的事如实说趋势。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p><strong>30 天不承诺做出爆款。</strong> 昊七七已经是榜第二、不缺爆款。承诺的是：用数据证明&quot;出爆款&quot;这件事变得更可复制，把几个高手的判断沉淀成新人也能用的规则，把重复的人肉活儿减下来。</p><hr><h2 id="价值分两类-交账方式完全不同" tabindex="-1">价值分两类，交账方式完全不同 <a class="header-anchor" href="#价值分两类-交账方式完全不同" aria-label="Permalink to &quot;价值分两类，交账方式完全不同&quot;">​</a></h2><p><strong>第一类：过程指标——我打包票，30 天一定交得出。</strong></p><p>这些完全在我手里，跟运气无关：素材有没有真正进流程（编号覆盖率）、数据能不能收回来复盘（回写完整率）、经验有没有沉淀（待验证假设条数）、人有没有少干活（日报耗时下降）。</p><p><strong>第二类：结果指标——我只给趋势，不给单点神话。</strong></p><p>CTR、3 秒留存、加购、ROI 受产品、价格、大盘、运气一堆因素影响，我不敢说&quot;我让 ROI 涨了多少&quot;。我给的是趋势方向：上了这套之后，测得更快、废稿更少、赢的元素被复用得更狠，所以这些指标的改善方向对不对。这种不抢功、不夸大，是工程师诚信的基本姿态。</p><hr><h2 id="_30-天看板" tabindex="-1">30 天看板 <a class="header-anchor" href="#_30-天看板" aria-label="Permalink to &quot;30 天看板&quot;">​</a></h2>',12)),r(n),t[1]||(t[1]=e("hr",null,null,-1)),t[2]||(t[2]=e("h2",{id:"_30-天排期",tabindex:"-1"},[d("30 天排期 "),e("a",{class:"header-anchor",href:"#_30-天排期","aria-label":'Permalink to "30 天排期"'},"​")],-1)),t[3]||(t[3]=e("p",null,"30 天不是另起炉灶，是把 Q3 那七天的样板往后滚三周，全在自有私店上做。",-1)),r(s,{steps:[{label:"第 1 周",title:"搭台灌库",desc:"两张飞书表建好、真实爆款素材灌进库、AI 打标、素材用到自家店投放、接上回写脚本、出日报。就是 Q3 那七天。",tag:"交付节点"},{label:"第 2 周",title:"第一轮实验",desc:"挑 1 个主推 SKU，先测封面入口。一个变量、几条对照，数据回写、出复盘草稿，开始攒规则。"},{label:"第 3 周",title:"第二、三轮实验",desc:"测前 3 秒钩子、测承接链路。规则库开始变厚，赢的元素进二创复用。"},{label:"第 4 周",title:"结账交接",desc:"至少 3 轮实验闭环、进投放的素材基本都有编号有回写有结论、10 条以上带数据支撑的待验证假设。摊开 30 天看板，交 SOP。",tag:"交付节点"}]}),t[4]||(t[4]=o('<hr><h2 id="这30天同时回答三个隐性问题" tabindex="-1">这30天同时回答三个隐性问题 <a class="header-anchor" href="#这30天同时回答三个隐性问题" aria-label="Permalink to &quot;这30天同时回答三个隐性问题&quot;">​</a></h2><p><strong>工作留痕。</strong> 这套东西本身就是留痕载体——每条素材有编号有历史、每次投放有记录、每轮实验有复盘草稿，不是凭印象说&quot;我做了什么&quot;，是翻得出来的账本。可以随时摊开给任何人看。</p><p><strong>可交接性。</strong> 第七天交 SOP 不是走形式，是这套东西能不能活过个人的关键。任何一个运营接手都能看懂、能跑，才是真交付。库里的数据和规则是公司资产，不绑在某个人身上。</p><p><strong>进度不等你来问。</strong> 第一周末做一次小对齐，确认方向没跑偏。此后进展主动同步，不需要被催。</p><hr><h2 id="诚实边界" tabindex="-1">诚实边界 <a class="header-anchor" href="#诚实边界" aria-label="Permalink to &quot;诚实边界&quot;">​</a></h2><p><strong>不承诺爆款不是甩锅，是立场。</strong> 30 天押爆款是赌博式承诺，不以信用赌运气。</p><p><strong>&quot;编号覆盖率 ≥80%&quot;是附条件的承诺。</strong> 它的分母是&quot;进入投放的素材&quot;，要让这成立，得有&quot;没编号不排期&quot;这条硬约束——这条需要管理层拍板（见 Q5）。点头，这个数可以担；不点，只能承诺持续爬升，无法兑现具体数字。这个前提条件在这里说清楚。</p><p><strong>&quot;10 条待验证假设&quot;不是&quot;10 条铁律&quot;。</strong> 30 天、1 个 SKU、3 轮实验，样本量撑不到统计显著，不拿噪声当规律。10 条带数据支撑的假设，标好适用条件，等更长周期验证。</p><p><strong>这张成绩单全在自有私店。</strong> 私店得有可跑的投放体量，这是承重假设（Q-C）。万一私店体量太小，把样板挪到 1-2 个最配合的代理店去跑，成绩单的逻辑不变，起跑点换个地方。</p>',11))])}const f=l(q,[["render",u]]);export{T as __pageData,f as default};
